    ('Pomito', 'Passierte Tomaten', 'https://images.openfoodfacts.org/images/products/803/279/334/3264/front_de.87.400.jpg', 'off_api', 'front', true, 'Front — EAN 8032793343264', 'front_8032793343264'),
    ('Barilla', 'Base per Bolognese', 'https://images.openfoodfacts.org/images/products/807/680/951/3654/front_en.85.400.jpg', 'off_api', 'front', true, 'Front — EAN 8076809513654', 'front_8076809513654'),
    ('Heinz', 'Tomato Frito', 'https://images.openfoodfacts.org/images/products/841/006/614/0374/front_de.8.400.jpg', 'off_api', 'front', true, 'Front — EAN 8410066140374', 'front_8410066140374'),
    ('Edeka', 'Tomaten fein Passiert', 'https://images.openfoodfacts.org/images/products/431/150/175/9059/front_de.8.400.jpg', 'off_api', 'front', true, 'Front — EAN 4311501759059', 'front_4311501759059'),
    ('Bio kClassic', 'Passierte Tomaten', 'https://images.openfoodfacts.org/images/products/805/032/721/0615/front_de.11.400.jpg', 'off_api', 'front', true, 'Front — EAN 8050327210615', 'front_8050327210615'),
    ('Knorr', 'Tomato al Gusto - Basilikum', 'https://images.openfoodfacts.org/images/products/871/060/472/5569/front_en.16.400.jpg', 'off_api', 'front', true, 'Front — EAN 8710604725569', 'front_8710604725569'),
    ('Bertolli', 'Sugo Arrabiata', 'https://images.openfoodfacts.org/images/products/871/224/723/2756/front_de.4.400.jpg', 'off_api', 'front', true, 'Front — EAN 8712247232756', 'front_8712247232756'),
    ('Alnatura', 'Tomatensauce Basilikum', 'https://images.openfoodfacts.org/images/products/410/442/021/3470/front_en.36.400.jpg', 'off_api', 'front', true, 'Front — EAN 4104420213470', 'front_4104420213470')
) AS d(brand, product_name, url, source, image_type, is_primary, alt_text, off_image_id)
JOIN products p ON p.country = 'DE' AND p.brand = d.brand AND p.product_name = d.product_name
  AND p.category = 'Sauces' AND p.is_deprecated IS NOT TRUE
ON CONFLICT (off_image_id) WHERE off_image_id IS NOT NULL DO UPDATE SET
  url = EXCLUDED.url,
  image_type = EXCLUDED.image_type,
  is_primary = EXCLUDED.is_primary,
  alt_text = EXCLUDED.alt_text;
